// TypeScript implementation for Partial and Required
interface PartialandRequiredPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processPartialandRequired(item: PartialandRequiredPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processPartialandRequired({ id: 1, title: 'Partial and Required', status: 'active' }));

